import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import HomeTopBar from '../components/HomeTopBar';
import './Tasks.css';

function Tasks() {
    const navigate = useNavigate();
    const [tasks, setTasks] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadTasks = async () => {
            const userSession = localStorage.getItem('user');
            if (!userSession) {
                navigate('/signin');
                return;
            }

            const user = JSON.parse(userSession);
            try {
                const response = await fetch(`http://localhost:4000/api/tasks/${user.id}`);
                const data = await response.json();
                setTasks(data);
            } catch (error) {
                console.error('Error loading tasks:', error);
            } finally {
                setLoading(false);
            }
        };

        loadTasks();
    }, [navigate]);

    const handleContinueTask = async (task) => {
        try {
            // Load task files
            const filesResponse = await fetch(`http://localhost:4000/api/tasks/${task.task_id}/files`);
            if (!filesResponse.ok) {
                throw new Error('Failed to load task files');
            }
            const filesData = await filesResponse.json();

            const folderInfo = {
                folderId: task.folder_path.split('/').pop(),
                taskName: task.task_name,
                labelClasses: task.annotations?.labelClasses || [],
                files: filesData.files || []
            };

            // Determine which page to navigate to
            // You might want to add a task_type field to your tasks.csv
            if (task.folder_path.includes('segmentation')) {
                navigate('/segmentation', { state: { folderInfo } });
            } else if (task.folder_path.includes('classification')) {
                navigate('/classification', { state: { folderInfo } });
            } else {
                navigate('/detection', { state: { folderInfo } });
            }
        } catch (error) {
            console.error('Error continuing task:', error);
            alert('Failed to load task files. Please try again.');
        }
    };

    if (loading) {
        return <div>Loading tasks...</div>;
    }

    return (
        <div className="tasks-container">
            <HomeTopBar />
            <div className="tasks-content">
                <h2>My Tasks</h2>
                <div className="tasks-grid">
                    {tasks.map((task) => (
                        <div key={task.task_id} className="task-card">
                            <h3>{task.task_name}</h3>
                            <p>Created: {new Date(task.created_at).toLocaleDateString()}</p>
                            <p>Status: {task.status}</p>
                            <button onClick={() => handleContinueTask(task)}>
                                Continue Task
                            </button>
                        </div>
                    ))}
                    {tasks.length === 0 && (
                        <p>No tasks found. Create a new task to get started!</p>
                    )}
                </div>
            </div>
        </div>
    );
}

export default Tasks;
